// Сохраняем лид в память воркфлоу (staticData), чтобы отдать чек-лист,
// когда ученик нажмёт кнопку в WhatsApp.
// ⚠️ staticData работает только в АКТИВНОМ (production) воркфлоу.
const sd = $getWorkflowStaticData('global');
sd.leads = sd.leads || {};

const b = $json.body || $json;
const wa = String(b.waPhone || '').replace(/\D/g, '');
if (!wa || wa.length < 11) {
  throw new Error('waPhone пустой или некорректный: ' + JSON.stringify(b.waPhone));
}

sd.leads[wa] = {
  name: b.name || 'друг',
  checklist: b.checklist || 'Чек-лист готовится — менеджер свяжется с тобой в ближайшее время.',
  uniShort: b.uniShort || '',
  phone: b.phone || wa,
  specialties: b.specialties || [],
  topUniversities: b.topUniversities || [],
  exams: b.exams || '',
  ts: b.ts || new Date().toISOString(),
  delivered: false
};

return [{ json: { wa, name: sd.leads[wa].name, uniShort: sd.leads[wa].uniShort || 'твои топ-вузы' } }];

