parameters.jsCode:
// Разбираем входящее событие Meta. Реагируем только на сообщения
// (статусы доставки/прочтения пропускаем — return []).
const sd = $getWorkflowStaticData('global');
sd.leads = sd.leads || {};

const body = $json.body || $json;
const value = body?.entry?.[0]?.changes?.[0]?.value;
const msg = value?.messages?.[0];
if (!msg) return [];

const wa = String(msg.from || '').replace(/\D/g, '');
const lead = sd.leads[wa];

// Кнопка «Получить чек-лист» или любое сообщение → шлём чек-лист.
// Если лида нет (написал незнакомый номер) — вежливый ответ-приглашение.
const text = lead
  ? lead.checklist
  : 'Привет! Чтобы получить персональный чек-лист поступления, пройди тест AI Career Mentor на нашем сайте 🎓';

if (lead) lead.delivered = true;

return [{ json: { wa, text } }];

parameters.jsonBody:
={{ JSON.stringify({
  messaging_product: 'whatsapp',
  to: $json.wa,
  type: 'text',
  text: { body: $json.text }
}) }}
